DECLARE
BEGIN
  INSERT INTO tmp VALUES (-1);
  INSERT INTO tmp VALUES (0);
  INSERT INTO tmp VALUES (1/0);  -- 制造异常
  EXCEPTION
      WHEN others THEN
          rollback;              -- 全部回滚 无数据
END; $$ LANGUAGE PLPGSQL;
