SELECT * FROM tmp;

truncate table tmp;
CREATE OR REPLACE PROCEDURE test_proc() AS $$ 
DECLARE
BEGIN
  INSERT INTO tmp VALUES (-1);
  INSERT INTO tmp VALUES (0);
  INSERT INTO tmp VALUES (1/0);  -- 制造异常
  EXCEPTION
      WHEN others THEN           -- 提交 无数据
